const raw = String(msg.payload?.content || '').trim();
const firstToken = raw.split(/\s+/)[0] || '';
msg.tnsnCommand = firstToken.toLowerCase().replace(/@.+$/, '');
return msg;

const chatId = msg.payload?.chatId || flow.get('chatId');
const opts = {
  reply_markup: JSON.stringify({
    inline_keyboard: [
      [
        { text: 'System Status', callback_data: 'ui:status' },
        { text: 'Recent Signals', callback_data: 'ui:signals' }
      ],
      [
        { text: 'Help', callback_data: 'ui:help' },
        { text: 'Refresh Menu', callback_data: 'ui:menu' }
      ]
    ]
  })
};
msg.payload = {
  chatId,
  type: 'message',
  content: [
    'TNSN Control UI',
    'Use the inline controls below to inspect the system.',
    'Slash commands also work: /menu, /status, /signals, /help'
  ].join('\n'),
  options: opts
};
return msg;

