const opts = {
  reply_markup: JSON.stringify({
    inline_keyboard: [
      [
        { text: 'Recent Signals', callback_data: 'ui:signals' },
        { text: 'Help', callback_data: 'ui:help' }
      ],
      [
        { text: 'Main Menu', callback_data: 'ui:menu' }
      ]
    ]
  })
};
msg.payload = {
  chatId,
  type: 'message',
  content: [
    'TNSN status: online',
    `timestamp: ${now}`,
    `signal_history: ${signalPath}`,
    `audit_log: ${auditPath}`,
    'services: supervisor=ready, auditable_agent=ready, signal_engine=ready'
  ].join('\n'),
  options: opts
};
return msg;

const chatId = msg.payload?.chatId || flow.get('chatId');
const lines = String(msg.payload || '').trim();
