};
return msg;

const chatId = msg.chatId || flow.get('chatId');
const classification = msg.classification || msg.topic || 'unclassified';
const score = msg.score ?? 'n/a';
const title = msg.title || msg.headline || 'Signal alert';
const summary = msg.summary || msg.payload?.summary || msg.payload?.description || '';
const opts = {
  reply_markup: JSON.stringify({
    inline_keyboard: [
      [
        { text: 'Recent Signals', callback_data: 'ui:signals' },
        { text: 'System Status', callback_data: 'ui:status' }
      ],
      [
        { text: 'Main Menu', callback_data: 'ui:menu' }
      ]
    ]
  })
};
msg.payload = {
  chatId,
  type: 'message',
  content: [
    '🚨 TNSN Signal Alert',
    `class: ${classification}`,
    `score: ${score}`,
    `title: ${title}`,
    summary ? `summary: ${summary}` : null
  ].filter(Boolean).join('\n'),
  options: opts
};
return msg;

